mapper.select:
SELECT  FROM STOCK
ORDER BY country ASC, market ASC, stock_code ASC
LIMIT #{pageSize} OFFSET #{offset}

SELECT  FROM STOCK
WHERE country = #{country}
ORDER BY market ASC, stock_code ASC
LIMIT #{pageSize} OFFSET #{offset}

SELECT  FROM STOCK
WHERE country = #{country}
ORDER BY stock_code ASC

SELECT  FROM STOCK
WHERE market = #{market} OR market_type = #{market}
ORDER BY stock_code ASC

SELECT  FROM STOCK
WHERE market_type = #{marketType}
ORDER BY stock_code ASC

SELECT  FROM STOCK
WHERE industry = #{industry}
ORDER BY stock_code ASC


SELECT  FROM STOCK
WHERE current_price >= #{minPrice}
  AND current_price <= #{maxPrice}
ORDER BY current_price DESC


SELECT  FROM STOCK
WHERE volume >= #{minVolume}
  AND volume <= #{maxVolume}
ORDER BY volume DESC
